import{_ as e,a as t,b as r,c as d}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as c,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Redundant Backup மற்றும் Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Other/redundant-backup-and-read-source.md","filePath":"ta/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),p={name:"ta/Other/redundant-backup-and-read-source.md"};function u(s,a,h,o,b,k){return n(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="redundant-backup-மற்றும்-read-source-switching" tabindex="-1">Redundant Backup மற்றும் Read Source Switching <a class="header-anchor" href="#redundant-backup-மற்றும்-read-source-switching" aria-label="Permalink to &quot;Redundant Backup மற்றும் Read Source Switching&quot;">​</a></h1><p>Redundant backup ஏற்கனவே uploaded file-க்கு கூடுதல் copy சேமிக்கும்.</p><p>primary file மற்றும் backup file இரண்டும் read sources ஆக பயன்படுத்தலாம். visitors-க்கு பொதுவாக வேறுபாடு தெரியாது. வேறுபாடு file எந்த storage channel-ல் இருந்து serve ஆகிறது என்பதே.</p><h2 id="redundant-backup-என்ன-செய்ய-முடியும்" tabindex="-1">Redundant Backup என்ன செய்ய முடியும் <a class="header-anchor" href="#redundant-backup-என்ன-செய்ய-முடியும்" aria-label="Permalink to &quot;Redundant Backup என்ன செய்ய முடியும்&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>extra copy சேமித்தல்</td><td>single channel failure risk குறைக்க files-ஐ மற்ற upload channel-க்கு backup.</td></tr><tr><td>read source switch</td><td>backup வெற்றி பிறகு file reads primary channel மற்றும் backup channel இடையே switch.</td></tr><tr><td>single-file backup</td><td>file details page-ல் இருந்து ஒரு file backup.</td></tr><tr><td>batch backup</td><td>admin page-ல் multiple files select செய்து ஒன்றாக backup.</td></tr><tr><td>global redundant backup</td><td>Other Settings-ல் folder அடிப்படையில் files backup.</td></tr></tbody></table><h2 id="redundant-backup-entry" tabindex="-1">Redundant Backup Entry <a class="header-anchor" href="#redundant-backup-entry" aria-label="Permalink to &quot;Redundant Backup Entry&quot;">​</a></h2><p>திறக்கவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Redundant backup" loading="lazy"></p><p>folder அல்லது all files-க்கு bulk backup சேர்க்க இதுவே சிறந்த entry.</p><p>backup channel manually தேர்வு செய்யலாம், அல்லது automatic switching தேர்வு செய்து ImgBed suitable backup channel கண்டுபிடிக்க விடலாம்.</p><h2 id="file-details-ல்-இருந்து-backup" tabindex="-1">File Details-ல் இருந்து Backup <a class="header-anchor" href="#file-details-ல்-இருந்து-backup" aria-label="Permalink to &quot;File Details-ல் இருந்து Backup&quot;">​</a></h2><p>admin panel-ல் file details page திறந்து backup கிளிக் செய்யவும்.</p><p><img src="'+t+'" alt="Backup in file details" loading="lazy"></p><p>ஒரு முக்கிய file-ஐ on demand backup செய்ய இது பொருத்தம்.</p><p>backup வெற்றி பிறகு file details page available read sources காட்டும்.</p><h2 id="selection-மூலம்-batch-backup" tabindex="-1">Selection மூலம் Batch Backup <a class="header-anchor" href="#selection-மூலம்-batch-backup" aria-label="Permalink to &quot;Selection மூலம் Batch Backup&quot;">​</a></h2><p>admin panel-ல் multiple files select செய்து batch backup run செய்யவும்.</p><p><img src="'+r+'" alt="Batch backup" loading="lazy"></p><p>ஒரு file group process செய்ய இது பொருத்தம்.</p><p>Selection backup, file details backup, Other Settings-ல் redundant backup அனைத்தும் ஒரே backup system பயன்படுத்தும். entry points மட்டும் வேறு.</p><h2 id="backup-பிறகு-read-source-switch" tabindex="-1">Backup பிறகு Read Source Switch <a class="header-anchor" href="#backup-பிறகு-read-source-switch" aria-label="Permalink to &quot;Backup பிறகு Read Source Switch&quot;">​</a></h2><p>backup complete ஆன பிறகு file details page read source switch செய்ய விடும்:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Description</th></tr></thead><tbody><tr><td>Primary channel</td><td>original upload channel-ல் இருந்து read.</td></tr><tr><td>Backup channel</td><td>backup channel-ல் இருந்து read.</td></tr></tbody></table><p><img src="'+d+'" alt="Switch read source after backup" loading="lazy"></p><p>file primary channel அல்லது backup channel-ல் இருந்து serve ஆகிறதா என்பதை visitors அறிய தேவையில்லை.</p><p>நீங்கள் தேர்வு செய்யும் read source, later file access-க்கு preferred source ஆகும்.</p><h2 id="backup-எப்போது-skip-ஆகும்" tabindex="-1">Backup எப்போது Skip ஆகும் <a class="header-anchor" href="#backup-எப்போது-skip-ஆகும்" aria-label="Permalink to &quot;Backup எப்போது Skip ஆகும்&quot;">​</a></h2><p>backup போது இவை skip ஆகும். இவை errors அல்ல.</p><table tabindex="0"><thead><tr><th>Case</th><th>Why It Is Skipped</th></tr></thead><tbody><tr><td>Already backed up</td><td>ஏற்கனவே backup உள்ள file மீண்டும் backup ஆகாது.</td></tr><tr><td>Primary and backup channels are the same</td><td>meaningful backup-க்கு copy வேறு channel-ல் இருக்க வேண்டும்.</td></tr><tr><td>No usable backup channel</td><td>பொருத்தமான alternative channel இல்லை.</td></tr></tbody></table><p>சுருக்கம்: backups வேறு channel-க்கு போக வேண்டும்; ஏற்கனவே backed-up files extra space மீண்டும் பயன்படுத்தாது.</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>Primary channel</td><td>file முதலில் upload ஆன channel.</td></tr><tr><td>Backup channel</td><td>redundant copy சேமிக்கும் channel.</td></tr><tr><td>Primary read source</td><td>file தற்போது primary channel-ல் இருந்து read ஆகிறது.</td></tr><tr><td>Backup read source</td><td>file தற்போது backup channel-ல் இருந்து read ஆகிறது.</td></tr></tbody></table><p>Primary மற்றும் backup read sources user-facing behavior ஒரே மாதிரி.</p><p>backup file available என்றால் backup read source-க்கு switch செய்த பிறகும் images, videos, download links இயங்கும்.</p><h2 id="file-delete-செய்தால்-என்ன-ஆகும்" tabindex="-1">File Delete செய்தால் என்ன ஆகும் <a class="header-anchor" href="#file-delete-செய்தால்-என்ன-ஆகும்" aria-label="Permalink to &quot;File Delete செய்தால் என்ன ஆகும்&quot;">​</a></h2><p>file delete செய்யும்போது ImgBed primary file மற்றும் backup file இரண்டையும் delete செய்யும்.</p>',37)])])}const y=c(p,[["render",u]]);export{g as __pageData,y as default};
